{"cmd":"$sql = @'
create temp table if not exists _name_search_hits (
  schema_name text,
  table_name text,
  column_name text,
  search_term text
) on commit drop;

truncate _name_search_hits;

do $$
declare
  c record;
  term text;
  terms text[] := array['marcel','liz','elizabeth','jen','derrick'];
  q text;
begin
  for c in
    select table_schema, table_name, column_name
    from information_schema.columns
    where table_schema not in ('pg_catalog','information_schema','pg_toast','extensions','graphql','graphql_public','supabase_migrations','vault','realtime','storage','auth')
      and data_type in ('text','character varying','character','json','jsonb','USER-DEFINED')
      and udt_name in ('text','varchar','bpchar','citext','json','jsonb')
      and exists (
        select 1
        from information_schema.tables t
        where t.table_schema = columns.table_schema
          and t.table_name = columns.table_name
          and t.table_type = 'BASE TABLE'
      )
    order by table_schema, table_name, ordinal_position
  loop
    foreach term in array terms loop
      q := format(
        'insert into _name_search_hits(schema_name, table_name, column_name, search_term)
         select %L, %L, %L, %L
         where exists (select 1 from %I.%I where %I::text ilike %L limit 1)',
        c.table_schema, c.table_name, c.column_name, term,
        c.table_schema, c.table_name, c.column_name, '%' || term || '%'
      );
      begin
        execute q;
      exception when others then
        null;
      end;
    end loop;
  end loop;
end $$;

select schema_name, table_name, column_name, string_agg(search_term, ', ' order by search_term) as matched_terms
from _name_search_hits
group by schema_name, table_name, column_name
order by schema_name, table_name, column_name;
'@
supabase db query --linked --output table $sql","workdir":"C:\repos\shared-db","yield_time_ms":30000,"max_output_tokens":40000}

