    action: folded === fold(original) ? "clean" : "normalize",
    reason: "normalized case/punctuation",
  };
}

const records = parseCsv(fs.readFileSync(inputPath, "utf8"));
const people = new Map();
const mappings = [];
const review = [];

function ensurePerson(name) {
  const key = fold(name);
  if (!people.has(key)) {
    people.set(key, {
      canonical_name: name,
      groups: new Set(),
      sources: Object.fromEntries(sourceColumns.map((source) => [source, 0])),
      rawBySource: Object.fromEntries(sourceColumns.map((source) => [source, new Set()])),
    });
  }
  return people.get(key);
}

for (const record of records) {
  const source = record.source_column;
  const raw = record.raw_value;
  const rowCount = Number(record.row_count || 0);
  const group = sourceGroupFor(source);
  if (!group) continue;

  const cleaned = cleanRawValue(raw);
  if (!cleaned.names.length) {
    review.push({
      source_column: source,
      raw_value: raw,
      row_count: rowCount,
      action: cleaned.action,
      reason: cleaned.reason,
    });
    continue;
  }

  for (const name of cleaned.names) {
    const person = ensurePerson(name);
    person.groups.add(group);
    person.sources[source] += rowCount;
    person.rawBySource[source].add(raw);
    mappings.push({
      source_column: source,
      raw_value: raw,
      canonical_name: name,
      people_group: group,
      row_count: rowCount,
      action: cleaned.action,
      reason: cleaned.reason,
    });
  }
}

const sortedPeople = [...people.values()].sort((a, b) => a.canonical_name.localeCompare(b.canonical_name));

const alignedBySource = sortedPeople.map((person) => {
  const row = {
    canonical_name: person.canonical_name,
    creative_designer: person.groups.has("creative_designer") ? person.canonical_name : "",
    technical_designer: person.groups.has("technical_designer") ? person.canonical_name : "",
    freelance_designer: person.groups.has("freelance_designer") ? person.canonical_name : "",
    artist: person.groups.has("artist") ? person.canonical_name : "",
  };
  for (const source of sourceColumns) {
    row[source] = person.sources[source] > 0 ? person.canonical_name : "";
    row[`${source} row_count`] = person.sources[source] || "";
    row[`${source} raw_values`] = [...person.rawBySource[source]].sort().join(" | ");
  }
  return row;
});

const sourceHeaders = [
  "canonical_name",
  "creative_designer",
  "technical_designer",
  "freelance_designer",
  "artist",
  ...sourceColumns.flatMap((source) => [source, `${source} row_count`, `${source} raw_values`]),
];

writeCsv("designer_artist_cleaned_aligned_by_source.csv", alignedBySource, sourceHeaders);

writeCsv(
  "designer_artist_cleaned_four_lists.csv",
  sortedPeople.map((person) => ({
    canonical_name: person.canonical_name,
    creative_designers: person.groups.has("creative_designer") ? person.canonical_name : "",
    technical_designers: person.groups.has("technical_designer") ? person.canonical_name : "",
    freelance_designers: person.groups.has("freelance_designer") ? person.canonical_name : "",
    artists: person.groups.has("artist") ? person.canonical_name : "",
  })),
  ["canonical_name", "creative_designers", "technical_designers", "freelance_designers", "artists"],
);

writeCsv(
  "designer_artist_raw_to_clean_mapping.csv",
  mappings.sort((a, b) => a.canonical_name.localeCompare(b.canonical_name) || a.source_column.localeCompare(b.source_column)),
  ["source_column", "raw_value", "canonical_name", "people_group", "row_count", "action", "reason"],
);

writeCsv(
  "designer_artist_cleanup_review.csv",
  review.sort((a, b) => b.row_count - a.row_count || a.source_column.localeCompare(b.source_column)),
  ["source_column", "raw_value", "row_count", "action", "reason"],
);

const summary = {
  people: sortedPeople.length,
  mappings: mappings.length,
  review: review.length,
  byGroup: Object.fromEntries(Object.keys(sourceGroups).map((group) => [
    group,
    sortedPeople.filter((person) => person.groups.has(group)).length,
  ])),
};

console.log(JSON.stringify(summary, null, 2));

